import React from 'react';
import Navbar from 'react-bootstrap/Navbar';
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
// import { LinkContainer } from 'react-router-bootstrap';

function Navigation() {
  return (
    <Navbar expand="lg" fixed="top" collapseOnSelect>
      <Container>
        <Navbar.Brand href="/">
          <img src="./images/track-and-rally-logo.png" alt="Track and Rally logo" height={40} />
          <span className="niveau" style={{ color: '#4D4D4D', fontSize: '1.3rem'}}>Track & Rally</span>
        </Navbar.Brand>
        <Navbar.Toggle aria-controls="responsive-navbar-nav" />
        <Navbar.Collapse id="responsive-navbar-nav" className="justify-content-end">
          <Nav>
            {/* <LinkContainer to="/" exact>
              <Nav.Link className="roboto">Home</Nav.Link>
            </LinkContainer>
            <LinkContainer to="/about">
              <Nav.Link className="roboto">About</Nav.Link>
            </LinkContainer>
            <LinkContainer to="/media">
              <Nav.Link className="roboto">Media</Nav.Link>
            </LinkContainer> */}
          </Nav>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  )
}

export default Navigation;
